-                    processOptionToken(token, stopAtNonOption);
+                    // Check if there is a current option that takes an argument
+                    // If so, and if this token is not a valid option by itself,
+                    // treat it as an argument to the current option
+                    if (currentOption != null && currentOption.hasArg())
+                    {
+                        String opt = token.substring(1); // get the option char without '-'
+                        if (!options.hasOption(opt))
+                        {
+                            // This token is not a valid option, so treat as argument
+                            tokens.add(token);
+                            currentOption = null;
+                        }
+                        else
+                        {
+                            // This is a valid option, so process normally
+                            processOptionToken(token, stopAtNonOption);
+                        }
+                    }
+                    else
