+                    }
                 }
                 else if (options.hasOption(token)) {
                 	tokens.add(token);
@@ -17,6 +38,27 @@
                 // requires bursting
                 else
                 {
-                    burstToken(token, stopAtNonOption);
+                    // Check if there is a current option that takes an argument
+                    // If so, treat this token as an argument even if it starts with '-'
+                    if (currentOption != null && currentOption.hasArg())
+                    {
+                        // Check if the first character after '-' is a valid option
+                        String firstOpt = String.valueOf(token.charAt(1));
+                        if (!options.hasOption(firstOpt))
+                        {
+                            // The first character is not a valid option, so treat entire token as argument
+                            tokens.add(token);
+                            currentOption = null;
+                        }
+                        else
+                        {
+                            // Burst it since it may be a combination of multiple flags
+                            burstToken(token, stopAtNonOption);
+                        }
+                    }
+                    else
+                    {
+                        burstToken(token, stopAtNonOption);
+                    }
                 }
             }
